SELECT a.attendance_id, a.employee_id, e.name AS employee_name, a.attendance_date, a.check_in_time, a.check_out_time, a.attendance_status, a.late_min, a.early_leave_min, a.overtime_hours, a.remark, a.created_at FROM attendance_info a LEFT JOIN employee_info e ON a.employee_id = e.employee_id
AND a.employee_id = #{employeeId}
AND e.name LIKE CONCAT('%', #{employeeName}, '%')
AND a.attendance_status = #{attendanceStatus}
AND a.attendance_date >= #{startDate}
AND a.attendance_date <= #{endDate}
ORDER BY a.attendance_date DESC, a.created_at DESC LIMIT #{pageSize} OFFSET #{pageNum}

SELECT COUNT(*)
FROM attendance_info a
LEFT JOIN employee_info e ON a.employee_id = e.employee_id


